-- Spreader Charts: auto-calculate opening setting for FertApp
-- Creates: spreaders, spreader_chart_entries
-- Alters: fert_dispatches (add spreader_id)
-- Updates: get_fert_dispatched_lines RPC (return row_width + spreader_id)

-- ════════════════════════════════════════════════════════════════════════════
-- 1. spreaders — one per physical spreader machine on the farm
-- ════════════════════════════════════════════════════════════════════════════

CREATE TABLE IF NOT EXISTS public.spreaders (
  id              uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  organisation_id uuid NOT NULL REFERENCES organisations(id),
  farm_id         uuid NOT NULL REFERENCES farms(id),
  name            text NOT NULL,
  fixed_speed_kmh numeric NOT NULL,
  created_at      timestamptz DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_spreaders_farm ON spreaders (farm_id);

ALTER TABLE spreaders ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Authenticated read spreaders" ON spreaders FOR SELECT TO authenticated USING (true);

-- ════════════════════════════════════════════════════════════════════════════
-- 2. spreader_chart_entries — lookup table: product × width × opening → kg/ha
-- ════════════════════════════════════════════════════════════════════════════

CREATE TABLE IF NOT EXISTS public.spreader_chart_entries (
  id           uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  spreader_id  uuid NOT NULL REFERENCES spreaders(id) ON DELETE CASCADE,
  product_id   uuid NOT NULL REFERENCES fert_products(id),
  width_m      numeric NOT NULL,
  opening      numeric NOT NULL,
  kg_per_ha    numeric NOT NULL,
  UNIQUE (spreader_id, product_id, width_m, opening)
);

CREATE INDEX IF NOT EXISTS idx_chart_entries_lookup ON spreader_chart_entries (spreader_id, product_id, width_m);

ALTER TABLE spreader_chart_entries ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Authenticated read spreader_chart_entries" ON spreader_chart_entries FOR SELECT TO authenticated USING (true);

-- ════════════════════════════════════════════════════════════════════════════
-- 3. Add spreader_id to fert_dispatches
-- ════════════════════════════════════════════════════════════════════════════

ALTER TABLE public.fert_dispatches ADD COLUMN IF NOT EXISTS spreader_id uuid REFERENCES spreaders(id);

-- ════════════════════════════════════════════════════════════════════════════
-- 4. Update get_fert_dispatched_lines — add row_width + spreader_id
-- ════════════════════════════════════════════════════════════════════════════

DROP FUNCTION IF EXISTS public.get_fert_dispatched_lines(uuid, uuid);
CREATE OR REPLACE FUNCTION public.get_fert_dispatched_lines(
  p_user_id uuid,
  p_farm_id uuid
)
RETURNS TABLE (
  line_id            uuid,
  dispatch_id        uuid,
  timing_id          uuid,
  timing_label       text,
  timing_sort        integer,
  product_id         uuid,
  product_name       text,
  product_unit       text,
  orchard_id         uuid,
  orchard_name       text,
  orchard_nr         integer,
  variety            text,
  section_name       text,
  ha                 numeric,
  rate_per_ha        numeric,
  total_qty          numeric,
  bag_weight_kg      numeric,
  row_width          numeric,
  spreader_id        uuid,
  confirmed          boolean,
  date_applied       date,
  actual_rate_per_ha numeric,
  actual_total_qty   numeric
)
LANGUAGE sql STABLE
AS $$
  SELECT
    fdo.line_id,
    fd.id AS dispatch_id,
    ft.id AS timing_id,
    ft.label AS timing_label,
    ft.sort_order AS timing_sort,
    fp.id AS product_id,
    fp.name AS product_name,
    fp.default_unit AS product_unit,
    fdo.orchard_id,
    o.name AS orchard_name,
    o.orchard_nr,
    o.variety,
    s.name AS section_name,
    frl.ha,
    frl.rate_per_ha,
    COALESCE(frl.total_qty, frl.rate_per_ha * COALESCE(frl.ha, 0)) AS total_qty,
    fp.bag_weight_kg,
    o.row_width,
    fd.spreader_id,
    COALESCE(fa.confirmed, false) AS confirmed,
    fa.date_applied,
    fa.actual_rate_per_ha,
    fa.actual_total_qty
  FROM fert_dispatch_orchards fdo
  JOIN fert_dispatches fd ON fd.id = fdo.dispatch_id
  JOIN fert_recommendation_lines frl ON frl.id = fdo.line_id
  JOIN orchards o ON o.id = fdo.orchard_id
  LEFT JOIN orchard_sections os ON os.orchard_id = o.id
  LEFT JOIN sections s ON s.id = os.section_id
  JOIN fert_timings ft ON ft.id = frl.timing_id
  JOIN fert_products fp ON fp.id = frl.product_id
  LEFT JOIN fert_applications fa ON fa.line_id = frl.id
  WHERE fd.farm_id = p_farm_id
    AND fd.status = 'active'
    AND fd.dispatched_to = p_user_id
  ORDER BY ft.sort_order, o.name;
$$;

